const chatInput = ($input.first().json.chatInput || '').trim();
if (chatInput.length > 5000) throw new Error('Input too long (max 5000 chars): ' + chatInput.length);

const inputType = chatInput.length > 500 ? 'full_story' : 'theme';

const universeId = 'univ-' + Date.now().toString(36) + '-' + Math.random().toString(36).substring(2, 8);

const wordSet = new Set(chatInput.toLowerCase().split(/[\s,.'!?;:()\-]+/).filter(Boolean));

const settingKeywords = {
  'forêt': { color: '#228B22', emoji: '🌲', setting: 'forêt' },
  'forest': { color: '#228B22', emoji: '🌲', setting: 'forêt' },
  'océan': { color: '#1E90FF', emoji: '🌊', setting: 'océan' },
  'mer': { color: '#1E90FF', emoji: '🌊', setting: 'mer' },
  'ocean': { color: '#1E90FF', emoji: '🌊', setting: 'océan' },
  'espace': { color: '#191970', emoji: '🚀', setting: 'espace' },
  'space': { color: '#191970', emoji: '🚀', setting: 'espace' },
  'volcan': { color: '#FF4500', emoji: '🌋', setting: 'volcan' },
  'montagne': { color: '#8B4513', emoji: '⛰️', setting: 'montagne' },
  'château': { color: '#DAA520', emoji: '🏰', setting: 'château' },
  'castle': { color: '#DAA520', emoji: '🏰', setting: 'château' },
  'pirate': { color: '#2F4F4F', emoji: '🏴‍☠️', setting: 'pirate' },
  'dragon': { color: '#B22222', emoji: '🐉', setting: 'dragon' },
  'école': { color: '#FF69B4', emoji: '🏫', setting: 'école' },
  'jardin': { color: '#90EE90', emoji: '🌸', setting: 'jardin' },
  'désert': { color: '#DEB887', emoji: '🏜️', setting: 'désert' },
  'neige': { color: '#B0E0E6', emoji: '❄️', setting: 'neige' },
  'glace': { color: '#B0E0E6', emoji: '❄️', setting: 'glace' },
};

let detectedSetting = { color: '#6B7DB3', emoji: '📖', setting: 'aventure' };
for (const [kw, meta] of Object.entries(settingKeywords)) {
  if (wordSet.has(kw) || chatInput.toLowerCase().includes(kw)) {
    detectedSetting = meta;
    break;
  }
}

return [{
  json: {
    chatInput,
    inputType,
    universeId,
    detectedSetting,
  }
}];

const item = $input.first().json;
const base = 'https://wddatxgqhdiosuhcztex.supabase.co/rest/v1/avatars';
const url = base + '?select=character_name,character_prompt,character_trait,gender';

return [{ json: {
  chatInput: item.chatInput,
  inputType: item.inputType,
  universeId: item.universeId,
  detectedSetting: item.detectedSetting,
  avatarFetchUrl: url
} }];

const items = $input.all();
const rows = [];
items.forEach(i => {
  const j = i.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && typeof j === 'object' && (j.character_name != null || j.body != null)) {
    if (Array.isArray(j.body)) rows.push(...j.body);
    else rows.push(j);
  }
});

const allAvatars = {};
let firstGender = 'girl';
rows.forEach(r => {
  if (r.character_name) {
    allAvatars[r.character_name.toLowerCase()] = {
      name: r.character_name,
      prompt: r.character_prompt || '',
      trait: r.character_trait || '',
      gender: r.gender || 'girl'
    };
    if (!firstGender || firstGender === 'girl') firstGender = r.gender || 'girl';
  }
});

let analyzeData = {};
try { analyzeData = $('Analyze Input').first().json; } catch(e) {}
const chatInput = (analyzeData.chatInput || '').toLowerCase();

const matched = {};
for (const [key, avatar] of Object.entries(allAvatars)) {
  if (chatInput.includes(key)) {
    matched[avatar.name] = avatar;
    firstGender = avatar.gender;
  }
}

if (Object.keys(matched).length === 0) {
  const fallbackKey = Object.keys(allAvatars)[0];
  if (fallbackKey) {
    matched[allAvatars[fallbackKey].name] = allAvatars[fallbackKey];
    firstGender = allAvatars[fallbackKey].gender;
  }
}

// characterBible = formatted for the OpenAI story prompt
const characterBible = Object.entries(matched)
  .map(([name, av]) => name + ': ' + av.prompt)
  .join('\n');

// Raw character_prompt values for direct injection into Gemini image prompts
const characterPrompts = Object.entries(matched)
  .map(([name, av]) => ({ name, prompt: av.prompt }))
  .filter(cp => cp.prompt);

const characterTraits = Object.entries(matched)
  .map(([name, av]) => av.trait ? name + ': ' + av.trait : '')
  .filter(Boolean)
  .join('\n');

const fallback = 'Hana: fillette de 8 ans, cheveux noirs courts au carre, petit ruban rouge cote gauche, grands yeux vert emeraude, tunique bleue aventuriere bordures dorees, bottes cuir marron, pendentif etoile lumineux.';

return [{ json: {
  characterBible: characterBible || fallback,
  characterPrompts,
  characterTraits,
  avatarGender: firstGender,
  characterCount: Object.keys(matched).length,
  matchedCharacters: Object.keys(matched),
  availableCharacters: Object.keys(allAvatars).map(k => allAvatars[k].name)
} }];

const raw = $input.first().json?.output?.[0]?.content?.[0]?.text;
if (!raw) throw new Error('No LLM output received. Check Generate story JSON node.');

let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json/g, '').replace(/```/g, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM returned invalid JSON: ' + e.message + ' | First 300 chars: ' + cleaned.substring(0, 300));
}

let pages = parsed.pages || (parsed.page ? [parsed.page] : []);
if (!pages || pages.length === 0) throw new Error('No pages found in LLM output.');

let preGenUniverseId = '';
let detectedSetting = { color: '#6B7DB3', emoji: '\u{1F4D6}' };
let characterBible = '';
let characterPrompts = [];
let characterTraits = '';
let avatarGender = 'girl';
try {
  const promptData = $('Build story prompt with bible').first().json;
  preGenUniverseId = promptData.universeId || '';
  detectedSetting = promptData.detectedSetting || detectedSetting;
  characterBible = promptData.characterBible || '';
  characterPrompts = promptData.characterPrompts || [];
  characterTraits = promptData.characterTraits || '';
} catch (e) {}
try {
  const m = $('Merge chatInput + character bible').first().json;
  avatarGender = m.avatarGender || 'girl';
} catch (e) {}

const universeId = preGenUniverseId || (parsed.universe && parsed.universe.id) || 'univ-fallback';

const universe = parsed.universe
  ? { ...parsed.universe, id: universeId, color: parsed.universe.color || detectedSetting.color, emoji: parsed.universe.emoji || detectedSetting.emoji }
  : { id: universeId, name: 'Univers genere', description: '', image_url: '', color: detectedSetting.color, emoji: detectedSetting.emoji, gender: avatarGender, display_order: 1 };

const BUCKET = 'BD-Pages';
const SUPABASE_URL = 'https://wddatxgqhdiosuhcztex.supabase.co';
const now = new Date().toISOString();

// Raw character_prompt as MODEL SHEET for Gemini
const modelSheetEntries = characterPrompts.length > 0
  ? characterPrompts.map(cp => cp.name + ':\n' + cp.prompt).join('\n\n')
  : characterBible;

const MODEL_SHEET =
'\n=== CHARACTER MODEL SHEET (MANDATORY - ZERO DEVIATION) ===\n\n'
+ modelSheetEntries
+ '\n\n=== CRITICAL RULES ===\n'
+ '- EXACT same character on ALL pages: same hair, face, eyes, skin tone, clothing, accessories, proportions and colors.\n'
+ '- ZERO creative deviation allowed.\n'
+ '\n'
+ '=== ABSOLUTE NO TEXT POLICY (CRITICAL) ===\n'
+ '- The image MUST contain ZERO text.\n'
+ '- NO page numbers.\n'
+ '- NO choices.\n'
+ '- NO UI elements.\n'
+ '- NO letters, words, symbols, or signs.\n'
+ '- NO speech bubbles or captions.\n'
+ '- NO hidden text in background.\n'
+ '- NO watermark or signature.\n'
+ '- If ANY text appears, the image is INVALID.\n'
+ '\n'
+ '=== PANEL INTEGRITY RULES (CRITICAL) ===\n'
+ '- Panels must be COMPLETE and FULLY visible.\n'
+ '- NO cut panels.\n'
+ '- NO half panels.\n'
+ '- NO panels going outside the image frame.\n'
+ '- ALL panel borders must be fully visible.\n'
+ '- Panels must be clean, closed shapes.\n'
+ '- NO broken or missing borders.\n'
+ '\n'
+ '=== PANEL CONSISTENCY ===\n'
+ '- Same panel style across ALL pages.\n'
+ '- Same border thickness (stroke).\n'
+ '- Same spacing between panels.\n'
+ '- Same rounded corners (if used).\n'
+ '- Do NOT change layout style randomly.\n'
+ '\n'
+ '=== SAFE LAYOUT RULE ===\n'
+ '- Use a clean storybook layout OR clean comic layout.\n'
+ '- Keep margins on all sides.\n'
+ '- NEVER place panels touching or crossing image edges.\n'
+ '\n'
+ '=== CHARACTER CONSISTENCY ===\n'
+ '- Face must remain IDENTICAL across all pages.\n'
+ '- Same hairstyle, same colors, same outfit.\n'
+ '- No random visual changes.\n'
+ '\n'
+ '=== COMPOSITION ===\n'
+ '- Character must be clearly visible.\n'
+ '- Do NOT cut head, face or body.\n'
+ '- Keep stable scale across pages.\n'
+ '\n'
+ '=== STYLE CONSISTENCY ===\n'
+ '- Same illustration style across all pages.\n'
+ '- Same line thickness and rendering.\n'
+ '\n'
+ '=== BACKGROUND ===\n'
+ '- Background must match the scene.\n'
+ '- MUST NOT contain text or symbols.\n'
+ '\n'
+ '=== COLORS & LIGHT ===\n'
+ '- Use soft, child-friendly colors.\n'
+ '- Avoid dark or aggressive tones.\n'
+ '\n'
+ '=== SAFETY ===\n'
+ '- No violence.\n'
+ '- No scary elements.\n'
+ '\n'
+ '=== HARD VALIDATION ===\n'
+ '- If ANY text is visible → REGENERATE.\n'
+ '- If ANY panel is cut or incomplete → REGENERATE.\n'
+ '- If layout is inconsistent → REGENERATE.\n'
+ '\n'
+ '=== END MODEL SHEET ===\n';

const TRAIT_CONTEXT = characterTraits
  ? '\nCharacter personality (expression/mood): ' + characterTraits + '\n'
  : '';

const hasBranching = pages[0] && pages[0].page_id != null;
const pageIdToNumber = {};
if (hasBranching) {
  pages.forEach((p, i) => { if (p.page_id) pageIdToNumber[p.page_id] = i + 1; });
}

// Per-page character_prompt reminder
const visualRecap = characterPrompts.length > 0
  ? characterPrompts.map(cp => 'REMINDER - ' + cp.name + ': ' + cp.prompt).join('\n')
  : '';

return pages.map((page, index) => {
  const pageNumber = hasBranching ? (index + 1) : (page.page_number || index + 1);
  const pageId = page.page_id || ('p' + pageNumber);
  const fileName = `${universeId}-page-${pageId}.png`;
  const storagePath = `${universeId}/${fileName}`;
  let choices = page.choices || [];
  if (hasBranching && choices.length) {
    choices = choices.map(c => ({
      ...c,
      next_page_number: c.next_page_id ? pageIdToNumber[c.next_page_id] : null
    }));
  }
  return {
    json: {
      universe,
      universeId,
      pageNumber,
      pageId,
      paragraphText: page.paragraph_text,
      sceneSummary: page.scene_summary,
      panels: page.panels,
      choices,
      storyStarts: parsed.story_starts || [],
      avatarGender,
      bucket: BUCKET,
      fileName,
      storagePath,
      supabaseUrl: SUPABASE_URL,
      createdAt: now,
      geminiPrompt: [
  MODEL_SHEET,
  TRAIT_CONTEXT,
  'Create a single children manga page illustration.',

  // ✅ FIX ICI
  'This is one page from a children story. Do not display any page number or identifier.',

  '',
  'STYLE: Soft pastel Japanese children manga. Warm colors. Expressive chibi characters.',
  'NO text, NO speech bubbles, NO typography, NO watermark, NO words anywhere.',

  // ✅ AJOUT ICI
  'CRITICAL:',
  '- Do NOT render any page id (like p5-1).',
  '- Do NOT render panel ids.',
  '- Do NOT render any identifiers or references.',

  '',
  'SCENE:',
  page.scene_summary || '',

  '',
  // ✅ FIX ICI
  'PANELS (for visual guidance only - NEVER render any id, label, or metadata):',
  JSON.stringify(page.panels, null, 2),

  '',
  visualRecap,

  '',
  'VERIFY: character matches model sheet exactly | no text in image | child-safe | same art style on all pages',
].join('\n')
    }
  };
});

const item = $input.first().json;
const u = item.universe;
if (!u || !u.id) {
  console.log('No universe data found, skipping upsert');
  return [];
}
const gender = item.avatarGender || u.gender || 'girl';

// Link this universe to the matched avatar characters
let avatarCharacterNames = [];
try {
  const bibleData = $('Build character bible').first().json;
  avatarCharacterNames = bibleData.matchedCharacters || [];
} catch(e) {}

return [{
  json: {
    id: u.id,
    name: u.name || 'Unnamed Universe',
    description: u.description || '',
    image_url: u.image_url || '',
    color: u.color || '#6B7DB3',
    emoji: u.emoji || '\u{1F4D6}',
    gender: gender,
    display_order: u.display_order || 1,
    avatar_character_names: avatarCharacterNames
  }
}];

const parseItem = $('Parse story JSON').first().json;
const starts = parseItem.storyStarts || [];
const universeId = parseItem.universeId;

if (!starts.length || !universeId) {
  console.log('No story_starts or missing universeId, skipping');
  return [];
}

// Generate a truly unique id per row so new generations INSERT instead of overwriting.
// Format: ss-{universeId_suffix}-{timestamp_base36}-{random}-{path_suffix}
// path_id preserves the original LLM label (start-A, start-B) for sorting + page mapping.
const ts = Date.now().toString(36);
const univSuffix = universeId.replace('univ-', '').substring(0, 8);

return starts.map(s => {
  const pathLabel = (s.id || 'start-x').toLowerCase();
  const pathSuffix = pathLabel.replace('start-', '');
  const rand = Math.random().toString(36).substring(2, 6);
  const uniqueId = `ss-${univSuffix}-${ts}-${rand}-${pathSuffix}`;
  return {
    json: {
      id: uniqueId,
      path_id: s.id || pathLabel,
      universe_id: universeId,
      title: s.title || 'Sans titre',
      text: s.text || '',
    }
  };
});

const items = $input.all();
return items.filter(item => item.json.universeId && item.json.pageNumber).map(item => ({
  json: {
    universe_id: item.json.universeId,
    page_number: item.json.pageNumber,
    text: item.json.paragraphText || '',
    scene_summary: item.json.sceneSummary || '',
    image_url: `${item.json.supabaseUrl}/storage/v1/object/public/${item.json.bucket}/${item.json.storagePath}`,
    created_at: item.json.createdAt
  }
}));

const items = $input.all();
const results = [];
for (const item of items) {
  if (!item.json.universeId || !item.json.pageNumber) continue;
  const choices = item.json.choices || [];
  choices.forEach((choice, index) => {
    const row = {
      id: choice.id || `choice-p${item.json.pageNumber}-${String.fromCharCode(97 + index)}`,
      universe_id: item.json.universeId,
      page_number: item.json.pageNumber,
      choice_order: index + 1,
      text: choice.text || '',
      created_at: item.json.createdAt
    };
    if (choice.next_page_number != null) row.next_page_number = choice.next_page_number;
    results.push({ json: row });
  });
}
return results;
